/*
 * Segregated free list dynamic memory allocator.
 *
 * Uses NUM_CLASSES explicit doubly-linked free lists organized by block size.
 * Size classes are powers of two starting from the minimum block size (32 bytes).
 * Placement uses first-fit within the smallest size class that can satisfy the
 * request, falling back to larger classes as needed.
 *
 * Free list heads are stored in a reserved region at the start of the heap,
 * accessed via the seg_lists pointer.
 *
 * Heap layout:
 *   [seg_list heads: NUM_CLASSES * WSIZE bytes (DSIZE-aligned)]
 *   [alignment padding: WSIZE]
 *   [prologue header: WSIZE]
 *   [prologue footer: WSIZE]
 *   [epilogue header: WSIZE]
 *   [free/allocated blocks ...]
 */

#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "memlib.h"
#include "mm.h"

/*********************************************************
 * NOTE TO STUDENTS: Before you do anything else, please
 * provide your team information in the following struct.
 ********************************************************/
team_t team = {
	/* Team name */
	"BSCS Bench",
	/* First member's full name */
	"BSCS Bench Agent",
	/* First member's NetID */
	"bscs1",
	/* Second member's full name (leave blank if none) */
	"",
	/* Second member's NetID (leave blank if none) */
	""
};

/* Basic constants and macros */
#define WSIZE       sizeof(void *)   /* Word and header/footer size (bytes) */
#define DSIZE       (2 * WSIZE)      /* Doubleword size (bytes) */
#define CHUNKSIZE   (1 << 12)        /* Extend heap by this amount (bytes) */
#define NUM_CLASSES 20               /* Number of segregated size classes */

#define MAX(x, y)   ((x) > (y) ? (x) : (y))

/* Pack a size and allocated bit into a word */
#define PACK(size, alloc)   ((size) | (alloc))

/* Read and write a word at address p */
#define GET(p)      (*(uintptr_t *)(p))
#define PUT(p, val) (*(uintptr_t *)(p) = (val))

/* Read the size and allocated fields from address p */
#define GET_SIZE(p)  (GET(p) & ~(DSIZE - 1))
#define GET_ALLOC(p) (GET(p) & 0x1)

/* Given block ptr bp, compute address of its header and footer */
#define HDRP(bp)  ((char *)(bp) - WSIZE)
#define FTRP(bp)  ((char *)(bp) + GET_SIZE(HDRP(bp)) - DSIZE)

/* Given block ptr bp, compute address of next and previous blocks */
#define NEXT_BLKP(bp)  ((char *)(bp) + GET_SIZE(((char *)(bp) - WSIZE)))
#define PREV_BLKP(bp)  ((char *)(bp) - GET_SIZE(((char *)(bp) - DSIZE)))

/* Access prev/next pointers in the payload of a free block */
#define FREE_PREV(bp)  (*(void **)(bp))
#define FREE_NEXT(bp)  (*((void **)(bp) + 1))

/* Global variables (scalars only) */
static void **seg_lists;  /* Pointer to segregated free list heads in heap */
static char  *heap_listp; /* Pointer to prologue block */

/* Internal helper prototypes */
static void *coalesce(void *bp);
static void *extend_heap(size_t words);
static void *find_fit(size_t asize);
static void  place(void *bp, size_t asize);
static void  insert_free(void *bp);
static void  remove_free(void *bp);
static int   get_class(size_t size);

/* Heap consistency checker prototypes */
static void checkblock(void *bp);
void        checkheap(bool verbose);
static void printblock(void *bp);

/*
 * get_class: Return the segregated list index for the given block size.
 *
 * Class 0: exactly minimum block size (2*DSIZE = 32 bytes)
 * Class i: (2^i * min, 2^(i+1) * min]  for i >= 1
 * Class NUM_CLASSES-1: everything larger
 */
static int
get_class(size_t size)
{
	int c = 0;
	size_t s = 2 * DSIZE; /* minimum block size */

	while (c < NUM_CLASSES - 1 && size > s) {
		s <<= 1;
		c++;
	}
	return (c);
}

/*
 * insert_free: Insert block bp at the head of the appropriate size class list.
 */
static void
insert_free(void *bp)
{
	int c = get_class(GET_SIZE(HDRP(bp)));
	void *head = seg_lists[c];

	FREE_PREV(bp) = NULL;
	FREE_NEXT(bp) = head;
	if (head != NULL)
		FREE_PREV(head) = bp;
	seg_lists[c] = bp;
}

/*
 * remove_free: Remove block bp from its segregated free list.
 */
static void
remove_free(void *bp)
{
	int c = get_class(GET_SIZE(HDRP(bp)));
	void *prev = FREE_PREV(bp);
	void *next = FREE_NEXT(bp);

	if (prev == NULL)
		seg_lists[c] = next;
	else
		FREE_NEXT(prev) = next;

	if (next != NULL)
		FREE_PREV(next) = prev;

	FREE_PREV(bp) = NULL;
	FREE_NEXT(bp) = NULL;
}

/*
 * mm_init: Initialize the memory manager.  Returns 0 on success, -1 on failure.
 *
 * Allocates a DSIZE-aligned region for the seg_list heads followed by the
 * standard prologue/epilogue structure, then extends the heap with an initial
 * free block.
 */
int
mm_init(void)
{
	char *p;
	/* Space for seg_list heads, rounded up to DSIZE boundary */
	size_t lists_size = NUM_CLASSES * WSIZE;
	lists_size = (lists_size + DSIZE - 1) & ~(DSIZE - 1);

	if ((p = mem_sbrk(lists_size + 4 * WSIZE)) == (void *)-1)
		return (-1);

	/* Initialize all seg_list heads to NULL */
	seg_lists = (void **)p;
	for (int i = 0; i < NUM_CLASSES; i++)
		seg_lists[i] = NULL;

	p += lists_size;

	/* Standard prologue/epilogue setup */
	PUT(p, 0);                             /* Alignment padding */
	PUT(p + (1 * WSIZE), PACK(DSIZE, 1)); /* Prologue header */
	PUT(p + (2 * WSIZE), PACK(DSIZE, 1)); /* Prologue footer */
	PUT(p + (3 * WSIZE), PACK(0, 1));     /* Epilogue header */
	heap_listp = p + (2 * WSIZE);

	/* Extend heap with initial free block */
	if (extend_heap(CHUNKSIZE / WSIZE) == NULL)
		return (-1);
	return (0);
}

/*
 * mm_malloc: Allocate a block with at least 'size' bytes of payload.
 * Returns a pointer to the allocated block, or NULL if size == 0 or OOM.
 */
void *
mm_malloc(size_t size)
{
	size_t asize;      /* Adjusted block size */
	size_t extendsize; /* Amount to extend heap if no fit */
	void *bp;

	if (size == 0)
		return (NULL);

	/* Adjust size: include overhead and enforce alignment */
	if (size <= DSIZE)
		asize = 2 * DSIZE;
	else
		asize = DSIZE * ((size + DSIZE + (DSIZE - 1)) / DSIZE);

	/* Search free lists */
	if ((bp = find_fit(asize)) != NULL) {
		place(bp, asize);
		return (bp);
	}

	/* No fit: extend heap */
	extendsize = MAX(asize, CHUNKSIZE);
	if ((bp = extend_heap(extendsize / WSIZE)) == NULL)
		return (NULL);
	place(bp, asize);
	return (bp);
}

/*
 * mm_free: Free the block pointed to by bp.
 */
void
mm_free(void *bp)
{
	size_t size;

	if (bp == NULL)
		return;

	size = GET_SIZE(HDRP(bp));
	PUT(HDRP(bp), PACK(size, 0));
	PUT(FTRP(bp), PACK(size, 0));
	coalesce(bp);
}

/*
 * mm_realloc: Resize the block pointed to by ptr to at least 'size' bytes.
 *
 * Tries in-place extension before falling back to malloc+copy:
 *   1. If shrinking: split in place (if remainder >= min block size).
 *   2. If growing and next block is free with enough combined space: absorb it.
 *   3. If growing and next block is free at end of heap (epilogue after it):
 *      absorb the free block + extend heap by exactly the shortfall.
 *   4. If next block IS the epilogue: extend heap by exactly what's needed.
 *   5. Fallback: malloc new block, copy, free old.
 */
void *
mm_realloc(void *ptr, size_t size)
{
	size_t oldsize, asize, combined, needed;
	void *newptr, *next_bp;
	bool next_alloc;

	if (size == 0) {
		mm_free(ptr);
		return (NULL);
	}

	if (ptr == NULL)
		return (mm_malloc(size));

	/* Adjusted requested size */
	if (size <= DSIZE)
		asize = 2 * DSIZE;
	else
		asize = DSIZE * ((size + DSIZE + (DSIZE - 1)) / DSIZE);

	oldsize = GET_SIZE(HDRP(ptr));

	/* Case 1: New size fits in current block — optionally split */
	if (asize <= oldsize) {
		if (oldsize - asize >= 2 * DSIZE) {
			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			next_bp = NEXT_BLKP(ptr);
			PUT(HDRP(next_bp), PACK(oldsize - asize, 0));
			PUT(FTRP(next_bp), PACK(oldsize - asize, 0));
			coalesce(next_bp);
		}
		return (ptr);
	}

	next_bp = NEXT_BLKP(ptr);
	next_alloc = GET_ALLOC(HDRP(next_bp));
	combined = oldsize + GET_SIZE(HDRP(next_bp));

	/* Case 2: Next block is free and large enough — absorb it */
	if (!next_alloc && combined >= asize) {
		remove_free(next_bp);
		if (combined - asize >= 2 * DSIZE) {
			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			next_bp = NEXT_BLKP(ptr);
			PUT(HDRP(next_bp), PACK(combined - asize, 0));
			PUT(FTRP(next_bp), PACK(combined - asize, 0));
			insert_free(next_bp);
		} else {
			PUT(HDRP(ptr), PACK(combined, 1));
			PUT(FTRP(ptr), PACK(combined, 1));
		}
		return (ptr);
	}

	/* Case 3: Next block is free but not enough, and it's at the end of heap.
	 * Absorb the free block and extend the heap by exactly the shortfall.
	 * extend_heap will automatically coalesce with the free block. */
	if (!next_alloc && GET_SIZE(HDRP(NEXT_BLKP(next_bp))) == 0) {
		needed = asize - combined;
		if (extend_heap(needed / WSIZE) == NULL)
			return (NULL);
		/* next_bp has been enlarged by coalescing with the extension */
		combined = oldsize + GET_SIZE(HDRP(next_bp));
		remove_free(next_bp);
		if (combined - asize >= 2 * DSIZE) {
			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			next_bp = NEXT_BLKP(ptr);
			PUT(HDRP(next_bp), PACK(combined - asize, 0));
			PUT(FTRP(next_bp), PACK(combined - asize, 0));
			insert_free(next_bp);
		} else {
			PUT(HDRP(ptr), PACK(combined, 1));
			PUT(FTRP(ptr), PACK(combined, 1));
		}
		return (ptr);
	}

	/* Case 4: Next block is the epilogue — extend heap by exactly what's needed */
	if (GET_SIZE(HDRP(next_bp)) == 0) {
		needed = asize - oldsize;
		if (extend_heap(needed / WSIZE) == NULL)
			return (NULL);
		/* next_bp is now a free block of size == needed */
		combined = oldsize + GET_SIZE(HDRP(next_bp));
		remove_free(next_bp);
		if (combined - asize >= 2 * DSIZE) {
			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			next_bp = NEXT_BLKP(ptr);
			PUT(HDRP(next_bp), PACK(combined - asize, 0));
			PUT(FTRP(next_bp), PACK(combined - asize, 0));
			insert_free(next_bp);
		} else {
			PUT(HDRP(ptr), PACK(combined, 1));
			PUT(FTRP(ptr), PACK(combined, 1));
		}
		return (ptr);
	}

	/* Case 5: Fallback — allocate new block, copy payload, free old block */
	newptr = mm_malloc(size);
	if (newptr == NULL)
		return (NULL);
	size_t copysize = oldsize - DSIZE;
	if (size < copysize)
		copysize = size;
	memcpy(newptr, ptr, copysize);
	mm_free(ptr);
	return (newptr);
}

/*
 * coalesce: Merge bp with any adjacent free blocks and add result to free list.
 * Returns pointer to the (possibly merged) free block.
 */
static void *
coalesce(void *bp)
{
	bool prev_alloc = GET_ALLOC(FTRP(PREV_BLKP(bp)));
	bool next_alloc = GET_ALLOC(HDRP(NEXT_BLKP(bp)));
	size_t size = GET_SIZE(HDRP(bp));

	if (prev_alloc && next_alloc) {
		/* Case 1: both neighbors allocated */
		insert_free(bp);
		return (bp);
	} else if (prev_alloc && !next_alloc) {
		/* Case 2: next block is free */
		void *next = NEXT_BLKP(bp);
		remove_free(next);
		size += GET_SIZE(HDRP(next));
		PUT(HDRP(bp), PACK(size, 0));
		PUT(FTRP(bp), PACK(size, 0));
		insert_free(bp);
		return (bp);
	} else if (!prev_alloc && next_alloc) {
		/* Case 3: previous block is free */
		void *prev = PREV_BLKP(bp);
		remove_free(prev);
		size += GET_SIZE(HDRP(prev));
		PUT(FTRP(bp), PACK(size, 0));
		PUT(HDRP(prev), PACK(size, 0));
		insert_free(prev);
		return (prev);
	} else {
		/* Case 4: both neighbors are free */
		void *prev = PREV_BLKP(bp);
		void *next = NEXT_BLKP(bp);
		remove_free(prev);
		remove_free(next);
		size += GET_SIZE(HDRP(prev)) + GET_SIZE(HDRP(next));
		PUT(HDRP(prev), PACK(size, 0));
		PUT(FTRP(next), PACK(size, 0));
		insert_free(prev);
		return (prev);
	}
}

/*
 * extend_heap: Extend the heap by 'words' words (rounded to even).
 * Returns the address of the new free block, or NULL on failure.
 */
static void *
extend_heap(size_t words)
{
	size_t size;
	void *bp;

	/* Allocate an even number of words to maintain alignment */
	size = (words % 2) ? (words + 1) * WSIZE : words * WSIZE;
	if ((bp = mem_sbrk(size)) == (void *)-1)
		return (NULL);

	/* Initialize free block header/footer and new epilogue */
	PUT(HDRP(bp), PACK(size, 0));
	PUT(FTRP(bp), PACK(size, 0));
	PUT(HDRP(NEXT_BLKP(bp)), PACK(0, 1));

	return (coalesce(bp));
}

/*
 * find_fit: Find a free block of at least asize bytes.
 *
 * Searches size classes from smallest-fitting upward.  Blocks adjacent to the
 * epilogue (i.e., the "right buffer" left by in-place realloc) are skipped
 * in favor of internal free blocks across all classes; they are used only as a
 * last resort.  This preserves the right buffer for future in-place realloc.
 */
static void *
find_fit(size_t asize)
{
	int start = get_class(asize);
	void *eol_block = NULL; /* fallback: the one block adjacent to epilogue */

	for (int c = start; c < NUM_CLASSES; c++) {
		for (void *bp = seg_lists[c]; bp != NULL; bp = FREE_NEXT(bp)) {
			if (GET_SIZE(HDRP(bp)) < asize)
				continue;
			if (GET_SIZE(HDRP(NEXT_BLKP(bp))) != 0)
				return (bp); /* non-epilogue-adjacent: use it */
			if (eol_block == NULL)
				eol_block = bp; /* save as last resort */
		}
	}
	return (eol_block);
}

/*
 * place: Allocate asize bytes at bp, splitting if the remainder >= min block size.
 */
static void
place(void *bp, size_t asize)
{
	size_t csize = GET_SIZE(HDRP(bp));

	remove_free(bp);

	if (csize - asize >= 2 * DSIZE) {
		PUT(HDRP(bp), PACK(asize, 1));
		PUT(FTRP(bp), PACK(asize, 1));
		void *next = NEXT_BLKP(bp);
		PUT(HDRP(next), PACK(csize - asize, 0));
		PUT(FTRP(next), PACK(csize - asize, 0));
		insert_free(next);
	} else {
		PUT(HDRP(bp), PACK(csize, 1));
		PUT(FTRP(bp), PACK(csize, 1));
	}
}

/*
 * The remaining routines are heap consistency checker routines.
 */

static void
checkblock(void *bp)
{
	if ((uintptr_t)bp % DSIZE)
		printf("Error: %p is not doubleword aligned\n", bp);
	if (GET(HDRP(bp)) != GET(FTRP(bp)))
		printf("Error: header does not match footer at %p\n", bp);
}

void
checkheap(bool verbose)
{
	void *bp;

	if (verbose)
		printf("Heap (%p):\n", heap_listp);

	if (GET_SIZE(HDRP(heap_listp)) != DSIZE || !GET_ALLOC(HDRP(heap_listp)))
		printf("Bad prologue header\n");
	checkblock(heap_listp);

	for (bp = heap_listp; GET_SIZE(HDRP(bp)) > 0; bp = NEXT_BLKP(bp)) {
		if (verbose)
			printblock(bp);
		checkblock(bp);
		/* Check that no two adjacent free blocks escaped coalescing */
		if (!GET_ALLOC(HDRP(bp)) && !GET_ALLOC(HDRP(NEXT_BLKP(bp))))
			printf("Error: consecutive free blocks at %p and %p\n",
			    bp, NEXT_BLKP(bp));
	}

	if (verbose)
		printblock(bp);
	if (GET_SIZE(HDRP(bp)) != 0 || !GET_ALLOC(HDRP(bp)))
		printf("Bad epilogue header\n");

	/* Check that every block in each free list is actually free */
	for (int c = 0; c < NUM_CLASSES; c++) {
		for (void *fp = seg_lists[c]; fp != NULL; fp = FREE_NEXT(fp)) {
			if (GET_ALLOC(HDRP(fp)))
				printf("Error: allocated block %p in free list class %d\n",
				    fp, c);
		}
	}
}

static void
printblock(void *bp)
{
	size_t hsize = GET_SIZE(HDRP(bp));
	bool halloc  = GET_ALLOC(HDRP(bp));
	size_t fsize = GET_SIZE(FTRP(bp));
	bool falloc  = GET_ALLOC(FTRP(bp));

	if (hsize == 0) {
		printf("%p: end of heap\n", bp);
		return;
	}
	printf("%p: header: [%zu:%c] footer: [%zu:%c]\n", bp,
	    hsize, (halloc ? 'a' : 'f'),
	    fsize, (falloc ? 'a' : 'f'));
}

